-- SALES EXECUTION OS V30 - PACK 1 FOUNDATION
create table if not exists public.sales_playbooks (id bigserial primary key,title text not null,segment text not null default 'general',objective text,script_body text,execution_steps jsonb not null default '[]'::jsonb,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.sales_objections (id bigserial primary key,objection text not null,category text not null default 'general',recommended_answer text not null,next_action text,risk_level text not null default 'medium',is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.sales_execution_actions (id bigserial primary key,lead_id bigint,family_id bigint,contract_id bigint,action_type text not null,action_title text not null,action_status text not null default 'pending',priority text not null default 'medium',due_at timestamptz,owner_user_id uuid,notes text,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.sales_quotes (id bigserial primary key,lead_id bigint,family_id bigint,contract_id bigint,quote_reference text,client_type text not null default 'b2c_family',package_name text not null,service_scope text,city text,duration_label text,price_amount numeric(12,2),currency text not null default 'MAD',discount_amount numeric(12,2) not null default 0,discount_reason text,approval_status text not null default 'not_required',quote_status text not null default 'draft',valid_until date,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.sales_handoffs (id bigserial primary key,lead_id bigint,family_id bigint,contract_id bigint,handoff_status text not null default 'draft',client_promise text,service_sold text,start_deadline timestamptz,schedule_summary text,city_zone text,caregiver_expectation text,payment_status text not null default 'pending',risk_notes text,manager_comment text,operations_acknowledged boolean not null default false,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.sales_deal_scores (id bigserial primary key,lead_id bigint,family_id bigint,score integer not null default 0,urgency_score integer not null default 0,budget_score integer not null default 0,authority_score integer not null default 0,service_fit_score integer not null default 0,payment_readiness_score integer not null default 0,closing_probability integer not null default 0,recommended_action text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint sales_deal_scores_range check (score between 0 and 100 and urgency_score between 0 and 100 and budget_score between 0 and 100 and authority_score between 0 and 100 and service_fit_score between 0 and 100 and payment_readiness_score between 0 and 100 and closing_probability between 0 and 100));
create index if not exists idx_sales_execution_actions_lead_id on public.sales_execution_actions(lead_id);
create index if not exists idx_sales_execution_actions_status on public.sales_execution_actions(action_status);
create index if not exists idx_sales_quotes_lead_id on public.sales_quotes(lead_id);
create index if not exists idx_sales_handoffs_contract_id on public.sales_handoffs(contract_id);
create index if not exists idx_sales_deal_scores_lead_id on public.sales_deal_scores(lead_id);
insert into public.sales_playbooks (title, segment, objective, script_body, execution_steps) values ('B2C Family Urgency Close','b2c_family','Move urgent family demand from inquiry to payment promise.','Confirm need, recommend package, handle trust objections, secure payment deadline.','["Confirm city and schedule","Recommend package","Clear objection","Secure payment promise","Prepare handoff"]'::jsonb),('B2B Institution Pilot Close','b2b','Convert institution demand into a controlled pilot or contract conversation.','Map decision maker, volume, compliance, schedule and pilot scope.','["Identify decision maker","Map volume","Define pilot","Quote","Schedule follow-up"]'::jsonb),('Payment Promise Recovery','general','Recover accepted deals blocked by payment delay.','Confirm blocker, set payment deadline, request proof, define activation consequence.','["Confirm reason","Set deadline","Send payment recap","Escalate if late"]'::jsonb);
insert into public.sales_objections (objection, category, recommended_answer, next_action, risk_level) values ('Price is high','price','Reframe around reliability, replacement control, support structure and the cost of unmanaged service failure.','Send package comparison and request decision deadline.','medium'),('I need to think','delay','Ask what is unclear, identify the blocker, recap the recommended option, and set a precise follow-up time.','Schedule follow-up action.','medium'),('Can I trust the caregiver?','trust','Explain AngelCare selection, support, tracking, replacement process and operational accountability.','Send trust/process recap.','high'),('Payment delay','payment','Confirm exact payment reason, deadline, method and proof needed before activation.','Create payment promise action.','high');
